import{_ as s,c as o,o as d,a1 as t,j as e,a as i,t as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Введение: OpenCode Agent Skills | opencode-agent-skills","description":"Изучите ключевую ценность и основные функции OpenCode Agent Skills. Освойте динамическое обнаружение навыков, внедрение контекста, сжатие и восстановление. Совместимость с Claude Code и автоматические рекомендации.","frontmatter":{"title":"Введение: OpenCode Agent Skills | opencode-agent-skills","sidebarTitle":"Пусть AI понимает ваши навыки","subtitle":"Введение: OpenCode Agent Skills","description":"Изучите ключевую ценность и основные функции OpenCode Agent Skills. Освойте динамическое обнаружение навыков, внедрение контекста, сжатие и восстановление. Совместимость с Claude Code и автоматические рекомендации.","tags":["Руководство для начинающих","Введение в плагин"],"prerequisite":[],"order":1},"headers":[],"relativePath":"ru/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"ru/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}'),r={name:"ru/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},p={tabindex:"0"};function u(a,l,c,h,g,k){return d(),o("div",null,[l[7]||(l[7]=t(`<h1 id="что-такое-opencode-agent-skills" tabindex="-1">Что такое OpenCode Agent Skills? <a class="header-anchor" href="#что-такое-opencode-agent-skills" aria-label="Permalink to &quot;Что такое OpenCode Agent Skills?&quot;">​</a></h1><h2 id="что-вы-сможете-делать-после-изучения" tabindex="-1">Что вы сможете делать после изучения <a class="header-anchor" href="#что-вы-сможете-делать-после-изучения" aria-label="Permalink to &quot;Что вы сможете делать после изучения&quot;">​</a></h2><ul><li>Понимать ключевую ценность плагина OpenCode Agent Skills</li><li>Осваивать основные функциональные возможности плагина</li><li>Понимать, как навыки автоматически обнаруживаются и загружаются</li><li>Различать разницу между этим плагином и другими решениями для управления навыками</li></ul><h2 id="текущие-трудности" tabindex="-1">Текущие трудности <a class="header-anchor" href="#текущие-трудности" aria-label="Permalink to &quot;Текущие трудности&quot;">​</a></h2><p>Возможно, вы сталкивались с такими ситуациями:</p><ul><li><strong>Разрозненное управление навыками</strong>: навыки разбросаны по проектам, пользовательским каталогам, кэшу плагинов и другим местам, и невозможно найти подходящий навык</li><li><strong>Чем дольше сессия, тем больше проблем</strong>: после долгих сессий ранее загруженные навыки теряют эффективность из-за сжатия контекста</li><li><strong>Тревога по поводу совместимости</strong>: беспокойство о том, что существующие навыки и плагины не будут работать после миграции с Claude Code</li><li><strong>Необходимость повторной настройки</strong>: для каждого проекта требуется повторная настройка навыков, отсутствует единый механизм управления навыками</li></ul><p>Все эти проблемы влияют на эффективность использования AI-ассистента.</p><h2 id="основная-концепция" tabindex="-1">Основная концепция <a class="header-anchor" href="#основная-концепция" aria-label="Permalink to &quot;Основная концепция&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong> — это система плагинов, предоставляющая возможности динамического обнаружения и управления навыками для OpenCode.</p><div class="info custom-block"><p class="custom-block-title">Что такое навык?</p><p>Навык (Skill) — это многократно используемый модуль, содержащий руководство по рабочим процессам AI. Обычно это каталог, содержащий файл <code>SKILL.md</code> (описывающий функциональность и методы использования навыка) и возможные вспомогательные файлы (документация, скрипты и т.д.).</p></div><p><strong>Ключевая ценность</strong>: реализация повторного использования навыков между проектами и сессиями через стандартизированный формат навыков (SKILL.md).</p><h3 id="техническая-архитектура" tabindex="-1">Техническая архитектура <a class="header-anchor" href="#техническая-архитектура" aria-label="Permalink to &quot;Техническая архитектура&quot;">​</a></h3><p>Плагин разработан на базе TypeScript + Bun + Zod и предоставляет 4 основных инструмента:</p><table tabindex="0"><thead><tr><th>Инструмент</th><th>Функция</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>Внедрение содержимого SKILL.md навыка в контекст сессии</td></tr><tr><td><code>read_skill_file</code></td><td>Чтение вспомогательных файлов из каталога навыков (документация, конфигурация и т.д.)</td></tr><tr><td><code>run_skill_script</code></td><td>Выполнение исполняемых скриптов в контексте каталога навыков</td></tr><tr><td><code>get_available_skills</code></td><td>Получение списка доступных в настоящее время навыков</td></tr></tbody></table><h2 id="основные-функциональные-характеристики" tabindex="-1">Основные функциональные характеристики <a class="header-anchor" href="#основные-функциональные-характеристики" aria-label="Permalink to &quot;Основные функциональные характеристики&quot;">​</a></h2><h3 id="_1-динамическое-обнаружение-навыков" tabindex="-1">1. Динамическое обнаружение навыков <a class="header-anchor" href="#_1-динамическое-обнаружение-навыков" aria-label="Permalink to &quot;1. Динамическое обнаружение навыков&quot;">​</a></h3><p>Плагин автоматически обнаруживает навыки из нескольких мест, отсортированных по приоритету:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (уровень проекта - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (уровень проекта - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (уровень пользователя - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (уровень пользователя - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/        (кэш плагинов)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (установленные плагины)</span></span></code></pre></div><p><strong>Правило</strong>: вступает в силу первый совпавший навык, последующие навыки с тем же именем игнорируются.</p><blockquote><p>Почему такой дизайн?</p><p>Навыки уровня проекта имеют приоритет над навыками уровня пользователя, поэтому вы можете настраивать поведение для конкретного проекта без влияния на глобальную конфигурацию.</p></blockquote><h3 id="_2-внедрение-контекста" tabindex="-1">2. Внедрение контекста <a class="header-anchor" href="#_2-внедрение-контекста" aria-label="Permalink to &quot;2. Внедрение контекста&quot;">​</a></h3><p>При вызове <code>use_skill</code> содержимое навыка внедряется в контекст сессии в формате XML:</p><ul><li><code>noReply: true</code> — AI не будет отвечать на внедренное сообщение</li><li><code>synthetic: true</code> — помечено как системно сгенерированное сообщение (не отображается в интерфейсе, не учитывается как ввод пользователя)</li></ul><p>Это означает, что содержимое навыка постоянно присутствует в контексте сессии, и даже если сессия растет и происходит сжатие контекста, навык остается доступным.</p><h3 id="_3-механизм-восстановления-при-сжатии" tabindex="-1">3. Механизм восстановления при сжатии <a class="header-anchor" href="#_3-механизм-восстановления-при-сжатии" aria-label="Permalink to &quot;3. Механизм восстановления при сжатии&quot;">​</a></h3><p>Когда OpenCode выполняет сжатие контекста (обычная операция для длительных сессий), плагин слушает событие <code>session.compacted</code> и автоматически повторно внедряет список доступных навыков.</p><p>Это гарантирует, что AI всегда знает, какие навыки доступны, даже в длительных сессиях, и не теряет способность доступа к навыкам из-за сжатия.</p><h3 id="_4-совместимость-с-claude-code" tabindex="-1">4. Совместимость с Claude Code <a class="header-anchor" href="#_4-совместимость-с-claude-code" aria-label="Permalink to &quot;4. Совместимость с Claude Code&quot;">​</a></h3><p>Плагин полностью совместим с системой навыков и плагинов Claude Code, поддерживая:</p><ul><li>Навыки Claude Code (<code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code>)</li><li>Кэш плагинов Claude (<code>~/.claude/plugins/cache/...</code>)</li><li>Рынок плагинов Claude (<code>~/.claude/plugins/marketplaces/...</code>)</li></ul><p>Это означает, что если вы ранее использовали Claude Code, после миграции на OpenCode вы все еще можете использовать существующие навыки и плагины.</p><h3 id="_5-автоматические-рекомендации-навыков" tabindex="-1">5. Автоматические рекомендации навыков <a class="header-anchor" href="#_5-автоматические-рекомендации-навыков" aria-label="Permalink to &quot;5. Автоматические рекомендации навыков&quot;">​</a></h3><p>Плагин отслеживает ваши сообщения, используя семантическое сходство для определения, связаны ли они с каким-либо доступным навыком:</p><ul><li>Вычисление вектора embedding сообщения</li><li>Вычисление косинусного сходства с описаниями всех навыков</li><li>Когда сходство превышает порог, внедрение оценочного промпта с рекомендацией AI загрузить соответствующий навык</li></ul><p>Этот процесс полностью автоматический, вам не нужно запоминать названия навыков или явно запрашивать их.</p><h3 id="_6-интеграция-superpowers-опционально" tabindex="-1">6. Интеграция Superpowers (опционально) <a class="header-anchor" href="#_6-интеграция-superpowers-опционально" aria-label="Permalink to &quot;6. Интеграция Superpowers (опционально)&quot;">​</a></h3><p>Плагин поддерживает рабочие процессы Superpowers, включенные через переменные окружения:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>После включения плагин автоматически обнаруживает навык <code>using-superpowers</code> и внедряет полные рабочие инструкции при инициализации сессии.</p><h2 id="сравнение-с-другими-решениями" tabindex="-1">Сравнение с другими решениями <a class="header-anchor" href="#сравнение-с-другими-решениями" aria-label="Permalink to &quot;Сравнение с другими решениями&quot;">​</a></h2>`,40)),e("table",p,[l[6]||(l[6]=e("thead",null,[e("tr",null,[e("th",null,"Решение"),e("th",null,"Особенности"),e("th",null,"Сценарии применения")])],-1)),e("tbody",null,[l[3]||(l[3]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"Динамическое обнаружение, восстановление при сжатии, автоматические рекомендации"),e("td",null,"Сценарии, требующие единого управления и автоматических рекомендаций")],-1)),e("tr",null,[l[1]||(l[1]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[l[0]||(l[0]=i("Автоматическая регистрация как инструмент ",-1)),e("code",null,"skills_"+n(a.name),1)]),l[2]||(l[2]=e("td",null,"Сценарии, требующие независимых вызовов инструментов",-1))]),l[4]||(l[4]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"Полный рабочий процесс разработки программного обеспечения"),e("td",null,"Проекты, требующие строгих спецификаций процессов")],-1)),l[5]||(l[5]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"Режим сервера MCP"),e("td",null,"Сценарии, требующие использования навыков в разных инструментах")],-1))])]),l[8]||(l[8]=t('<p>Причины выбора этого плагина:</p><ul><li>✅ <strong>Нулевая конфигурация</strong>: автоматическое обнаружение и управление навыками</li><li>✅ <strong>Интеллектуальные рекомендации</strong>: автоматические рекомендации соответствующих навыков на основе семантического соответствия</li><li>✅ <strong>Восстановление при сжатии</strong>: стабильная и надежная работа в длительных сессиях</li><li>✅ <strong>Совместимость</strong>: бесшовная миграция навыков Claude Code</li></ul><h2 id="резюме-урока" tabindex="-1">Резюме урока <a class="header-anchor" href="#резюме-урока" aria-label="Permalink to &quot;Резюме урока&quot;">​</a></h2><p>Плагин OpenCode Agent Skills предоставляет OpenCode полные возможности управления навыками через механизмы динамического обнаружения, внедрения контекста и восстановления при сжатии. Его ключевая ценность заключается в следующем:</p><ul><li><strong>Автоматизация</strong>: снижение нагрузки от ручной настройки и запоминания названий навыков</li><li><strong>Стабильность</strong>: навыки всегда доступны в длительных сессиях</li><li><strong>Совместимость</strong>: бесшовная интеграция с существующей экосистемой Claude Code</li></ul><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../installation/">Установка OpenCode Agent Skills</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как добавить плагин в конфигурацию OpenCode</li><li>Как проверить правильность установки плагина</li><li>Как настроить режим локальной разработки</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть исходный код</strong></summary><blockquote><p>Обновлено: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Вход плагина и обзор функций</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>Список ключевых функциональных возможностей</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>Приоритет обнаружения навыков</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>Внедрение синтетических сообщений</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Механизм восстановления при сжатии</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>Модуль семантического сопоставления</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code>: используемая модель embedding</li><li><code>SIMILARITY_THRESHOLD = 0.35</code>: порог семантического сходства</li><li><code>TOP_K = 5</code>: максимальное количество навыков, возвращаемых при автоматической рекомендации</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>discoverAllSkills()</code>: обнаружение навыков из нескольких мест</li><li><code>use_skill()</code>: внедрение содержимого навыка в контекст сессии</li><li><code>matchSkills()</code>: сопоставление соответствующих навыков на основе семантического сходства</li><li><code>injectSyntheticContent()</code>: внедрение синтетических сообщений в сессию</li></ul></details>',10))])}const C=s(r,[["render",u]]);export{m as __pageData,C as default};
